# Planify | Etapa 10.0.2 - Unificacao visual profissional
# ASCII-only applicator. Writes UTF-8 files from Base64 to avoid accent corruption.
$ErrorActionPreference = "Stop"

$root = (Get-Location).Path
if (!(Test-Path (Join-Path $root "package.json"))) {
  throw "Execute este script dentro de C:\planify"
}

$stamp = Get-Date -Format "yyyy-MM-dd-HH-mm-ss"
$backupDir = Join-Path $root "backups\etapa-10-0-2-unificacao-visual-$stamp"

function Ensure-Dir {
  param([string]$Path)
  if (!(Test-Path $Path)) {
    New-Item -ItemType Directory -Path $Path -Force | Out-Null
  }
}

function Backup-File {
  param([string]$RelativePath)
  $full = Join-Path $root $RelativePath
  if (Test-Path $full) {
    $dest = Join-Path $backupDir $RelativePath
    Ensure-Dir (Split-Path $dest -Parent)
    Copy-Item $full $dest -Force
  }
}

function Write-Base64File {
  param(
    [string]$RelativePath,
    [string]$Base64
  )

  $full = Join-Path $root $RelativePath
  Ensure-Dir (Split-Path $full -Parent)
  Backup-File $RelativePath

  $bytes = [Convert]::FromBase64String($Base64)
  [System.IO.File]::WriteAllBytes($full, $bytes)
  Write-Host "OK: $RelativePath" -ForegroundColor Green
}

Ensure-Dir $backupDir

Write-Host ""
Write-Host "=== Planify | Etapa 10.0.2 - Unificacao visual profissional ===" -ForegroundColor Cyan
Write-Host "Backup: $backupDir" -ForegroundColor DarkCyan
Write-Host ""

Write-Base64File "src/lib/pro/planifyTools.ts" ""

Write-Base64File "src/lib/studio/planifyStudioConfig.ts" ""

Write-Base64File "src/components/pro/PlanifyIcons.tsx" ""

Write-Base64File "src/components/pro/PlanifyBrand.tsx" ""

Write-Base64File "src/components/pro/PlanifyAppFrame.tsx" ""

Write-Base64File "src/components/studio/PlanifyStudioShell.tsx" ""

Write-Base64File "src/components/premium/PremiumAccessGate.tsx" ""

Write-Base64File "src/app/api/premium/status/route.ts" ""

Write-Base64File "src/app/login/page.tsx" ""

Write-Base64File "src/app/page.tsx" ""

Write-Base64File "src/app/dashboard/page.tsx" "aW1wb3J0IFBsYW5pZnlTdHVkaW9TaGVsbCBmcm9tICJAL2NvbXBvbmVudHMvc3R1ZGlvL1BsYW5pZnlTdHVkaW9TaGVsbCI7CgpleHBvcnQgZGVmYXVsdCBmdW5jdGlvbiBEYXNoYm9hcmRQYWdlKCkgewogIHJldHVybiA8UGxhbmlmeVN0dWRpb1NoZWxsIC8+Owp9Cg=="

Write-Base64File "src/app/materiais/page.tsx" ""

Write-Base64File "src/app/api/materiais/gerar/route.ts" ""

Write-Host ""
Write-Host "=== Limpando scripts antigos quebrados, se existirem ===" -ForegroundColor Cyan
Remove-Item ".\scripts\planify-etapa-10-0-studio.ps1" -Force -ErrorAction SilentlyContinue

Write-Host ""
Write-Host "=== Build de producao ===" -ForegroundColor Cyan
npm run build

if ($LASTEXITCODE -ne 0) {
  throw "Build falhou. Commit e push cancelados para proteger a Vercel."
}

Write-Host ""
Write-Host "=== Git add/commit/push ===" -ForegroundColor Cyan

git status --short

git add -- `
src/app/page.tsx `
src/app/dashboard/page.tsx `
src/app/login/page.tsx `
src/app/materiais/page.tsx `
src/app/api/materiais/gerar/route.ts `
src/app/api/premium/status/route.ts `
src/components/pro/PlanifyIcons.tsx `
src/components/pro/PlanifyBrand.tsx `
src/components/pro/PlanifyAppFrame.tsx `
src/components/studio/PlanifyStudioShell.tsx `
src/components/premium/PremiumAccessGate.tsx `
src/lib/pro/planifyTools.ts `
src/lib/studio/planifyStudioConfig.ts `
scripts/planify-etapa-10-0-2-unificacao-visual.ps1

$changes = git diff --cached --name-only

if (-not $changes) {
  Write-Host "Nenhuma alteracao nova para commit." -ForegroundColor Yellow
} else {
  git commit -m "fix: unificar visual profissional e acesso premium"
}

$branch = git branch --show-current
if (-not $branch) {
  throw "Nao consegui identificar a branch atual."
}

git push origin $branch

Write-Host ""
Write-Host "=== Concluido ===" -ForegroundColor Green
Write-Host "Build passou, commit/push finalizado. A Vercel deve implantar a branch: $branch" -ForegroundColor Green
